// Confirmation modal
export function Modal({ open, title, children, onClose }) {
  if (!open) return null
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center">
      <div className="absolute inset-0 bg-black/40" onClick={onClose} />
      <div className="relative bg-white rounded-xl shadow-2xl w-full max-w-md mx-4 animate-fade-in">
        <div className="flex items-center justify-between px-6 py-4 border-b border-gray-100">
          <h3 className="font-bold text-lg" style={{ color: '#042954' }}>{title}</h3>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-600">✕</button>
        </div>
        <div className="p-6">{children}</div>
      </div>
    </div>
  )
}

// Pagination
export function Pagination({ page, totalPages, onChange }) {
  const pages = Array.from({ length: totalPages }, (_, i) => i + 1)
  return (
    <div className="flex items-center gap-2 mt-4 justify-end">
      <button
        onClick={() => onChange(Math.max(1, page - 1))}
        disabled={page === 1}
        className="page-btn disabled:opacity-40"
      >
        ‹
      </button>
      {pages.map(p => (
        <button
          key={p}
          onClick={() => onChange(p)}
          className={`page-btn ${p === page ? 'active' : ''}`}
        >
          {p}
        </button>
      ))}
      <button
        onClick={() => onChange(Math.min(totalPages, page + 1))}
        disabled={page === totalPages}
        className="page-btn disabled:opacity-40"
      >
        ›
      </button>
    </div>
  )
}

// Search + filter bar
export function FilterBar({ children }) {
  return (
    <div className="flex flex-wrap gap-3 items-end p-4 border-b border-gray-100">
      {children}
    </div>
  )
}

import { createContext, useContext, useEffect, useState } from 'react'
import { supabase } from '../services/supabase'

const AuthContext = createContext(null)

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null)
  const [profile, setProfile] = useState(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    // Get initial session
    supabase.auth.getSession().then(({ data: { session } }) => {
      setUser(session?.user ?? null)
      if (session?.user) fetchProfile(session.user.id)
      else setLoading(false)
    })

    // Listen for auth changes
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user ?? null)
      if (session?.user) fetchProfile(session.user.id)
      else {
        setProfile(null)
        setLoading(false)
      }
    })

    return () => subscription.unsubscribe()
  }, [])

  async function fetchProfile(userId) {
    try {
      const { data, error } = await supabase
        .from('users')
        .select('*')
        .eq('id', userId)
        .single()

      if (!error && data) setProfile(data)
    } catch (err) {
      console.error('Error fetching profile:', err)
    } finally {
      setLoading(false)
    }
  }

  async function signIn(email, password) {
    const { data, error } = await supabase.auth.signInWithPassword({ email, password })
    if (error) throw error
    return data
  }

  async function signUp(email, password, userData) {
    const { data, error } = await supabase.auth.signUp({ email, password })
    if (error) throw error

    if (data.user) {
      // Insert into users table
      const { error: profileError } = await supabase.from('users').insert({
        id: data.user.id,
        name: userData.name,
        email: email,
        role: userData.role || 'student',
      })
      if (profileError) throw profileError

      // If student, insert student record
      if (userData.role === 'student' || !userData.role) {
        await supabase.from('students').insert({
          id: data.user.id,
          register_no: userData.register_no || '',
          department: userData.department || '',
          year: userData.year || 1,
        })
      }
    }
    return data
  }

  async function signOut() {
    const { error } = await supabase.auth.signOut()
    if (error) throw error
    setProfile(null)
    setUser(null)
  }

  async function resetPassword(email) {
    const { error } = await supabase.auth.resetPasswordForEmail(email)
    if (error) throw error
  }

  const value = { user, profile, loading, signIn, signUp, signOut, resetPassword, fetchProfile }

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>
}

export function useAuth() {
  const context = useContext(AuthContext)
  if (!context) throw new Error('useAuth must be used within AuthProvider')
  return context
}

import { useState, useEffect, useCallback } from 'react'
import { supabase } from '../services/supabase'
import toast from 'react-hot-toast'

// Generic fetch hook
export function useFetch(table, options = {}) {
  const [data, setData] = useState([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)

  const fetch = useCallback(async () => {
    setLoading(true)
    try {
      let query = supabase.from(table).select(options.select || '*')
      if (options.filter) query = query.eq(options.filter.column, options.filter.value)
      if (options.order) query = query.order(options.order.column, { ascending: options.order.ascending ?? false })
      if (options.limit) query = query.limit(options.limit)

      const { data: result, error: err } = await query
      if (err) throw err
      setData(result || [])
    } catch (err) {
      setError(err.message)
      console.error(`Error fetching ${table}:`, err)
    } finally {
      setLoading(false)
    }
  }, [table])

  useEffect(() => { fetch() }, [fetch])

  return { data, loading, error, refetch: fetch, setData }
}

// Students hook
export function useStudents() {
  const [students, setStudents] = useState([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)

  const fetchStudents = useCallback(async (filters = {}) => {
    setLoading(true)
    try {
      let query = supabase
        .from('students')
        .select(`*, users(id, name, email, role)`)
        .order('created_at', { ascending: false })

      if (filters.department) query = query.eq('department', filters.department)
      if (filters.year) query = query.eq('year', filters.year)
      if (filters.search) {
        query = query.or(`register_no.ilike.%${filters.search}%`)
      }

      const { data, error: err } = await query
      if (err) throw err
      setStudents(data || [])
    } catch (err) {
      setError(err.message)
      toast.error('Failed to load students')
    } finally {
      setLoading(false)
    }
  }, [])

  useEffect(() => { fetchStudents() }, [fetchStudents])

  return { students, loading, error, fetchStudents }
}

