// Attendance hook
export function useAttendance() {
  const [attendance, setAttendance] = useState([])
  const [loading, setLoading] = useState(false)

  const fetchAttendance = useCallback(async (date, department, year) => {
    setLoading(true)
    try {
      let query = supabase
        .from('attendance')
        .select(`*, students(id, register_no, department, year, users(name))`)
        .eq('date', date)

      if (department) query = query.eq('students.department', department)
      if (year) query = query.eq('students.year', year)

      const { data, error } = await query
      if (error) throw error
      setAttendance(data || [])
    } catch (err) {
      toast.error('Failed to load attendance')
    } finally {
      setLoading(false)
    }
  }, [])

  const markAttendance = async (records) => {
    try {
      // Upsert attendance records
      const { error } = await supabase
        .from('attendance')
        .upsert(records, { onConflict: 'student_id,date' })

      if (error) throw error
      toast.success('Attendance saved successfully!')
      return true
    } catch (err) {
      toast.error(err.message || 'Failed to save attendance')
      return false
    }
  }

  return { attendance, loading, fetchAttendance, markAttendance }
}

// Tests hook
export function useTests(teacherId = null) {
  const [tests, setTests] = useState([])
  const [loading, setLoading] = useState(true)

  const fetchTests = useCallback(async () => {
    setLoading(true)
    try {
      let query = supabase
        .from('tests')
        .select(`*, teachers(id, users(name)), questions(id)`)
        .order('created_at', { ascending: false })

      if (teacherId) query = query.eq('teacher_id', teacherId)

      const { data, error } = await query
      if (error) throw error
      setTests(data || [])
    } catch (err) {
      toast.error('Failed to load tests')
    } finally {
      setLoading(false)
    }
  }, [teacherId])

  useEffect(() => { fetchTests() }, [fetchTests])

  const createTest = async (testData) => {
    try {
      const { data, error } = await supabase
        .from('tests')
        .insert(testData)
        .select()
        .single()

      if (error) throw error
      toast.success('Test created successfully!')
      fetchTests()
      return data
    } catch (err) {
      toast.error(err.message || 'Failed to create test')
      return null
    }
  }

  return { tests, loading, fetchTests, createTest }
}

// Results hook
export function useResults(studentId = null, testId = null) {
  const [results, setResults] = useState([])
  const [loading, setLoading] = useState(true)

  const fetchResults = useCallback(async () => {
    setLoading(true)
    try {
      let query = supabase
        .from('results')
        .select(`*, students(id, register_no, users(name)), tests(id, title)`)
        .order('created_at', { ascending: false })

      if (studentId) query = query.eq('student_id', studentId)
      if (testId) query = query.eq('test_id', testId)

      const { data, error } = await query
      if (error) throw error
      setResults(data || [])
    } catch (err) {
      toast.error('Failed to load results')
    } finally {
      setLoading(false)
    }
  }, [studentId, testId])

  useEffect(() => { fetchResults() }, [fetchResults])

  return { results, loading, fetchResults }
}

import { useState, useEffect } from 'react'
import { Calendar, Check, X, Filter, Save } from 'lucide-react'
import { PageHeader, Spinner } from '../../components/UI'
import { supabase } from '../../services/supabase'
import toast from 'react-hot-toast'

const departments = ['Computer Science', 'Mathematics', 'Physics', 'Chemistry', 'Biology', 'English']

// Format today's date as YYYY-MM-DD
function today() {
  return new Date().toISOString().split('T')[0]
}

export default function Attendance() {
  const [date, setDate] = useState(today())
  const [department, setDepartment] = useState('')
  const [year, setYear] = useState('')
  const [students, setStudents] = useState([])
  const [loadingStudents, setLoadingStudents] = useState(false)
  const [attendance, setAttendance] = useState({}) // { studentId: 'present' | 'absent' }
  const [saving, setSaving] = useState(false)

  useEffect(() => {
    if (department) fetchStudentsWithAttendance()
  }, [date, department, year])

  async function fetchStudentsWithAttendance() {
    setLoadingStudents(true)
    try {
      // Fetch students
      let q = supabase
        .from('students')
        .select('id, register_no, department, year, users(name)')
        .eq('department', department)

      if (year) q = q.eq('year', parseInt(year))
      const { data: studs, error } = await q
      if (error) throw error

      // Fetch existing attendance for this date
      const studentIds = studs?.map(s => s.id) || []
      const { data: attData } = await supabase
        .from('attendance')
        .select('student_id, status')
        .eq('date', date)
        .in('student_id', studentIds)

      // Build attendance map
      const attMap = {}
      attData?.forEach(a => { attMap[a.student_id] = a.status })

      setStudents(studs || [])
      setAttendance(attMap)
    } catch (err) {
      toast.error('Failed to load students')
    } finally {
      setLoadingStudents(false)
    }
  }

  function toggleStatus(studentId) {
    setAttendance(prev => ({
      ...prev,
      [studentId]: prev[studentId] === 'present' ? 'absent'
        : prev[studentId] === 'absent' ? 'present'
        : 'present'
    }))
  }

  function markAll(status) {
    const map = {}
    students.forEach(s => { map[s.id] = status })
    setAttendance(map)
  }

  async function handleSave() {
    if (students.length === 0) return toast.error('No students loaded')
    setSaving(true)
    try {
      const records = students.map(s => ({
        student_id: s.id,
        date: date,
        status: attendance[s.id] || 'absent',
      }))

      const { error } = await supabase
        .from('attendance')
        .upsert(records, { onConflict: 'student_id,date' })

      if (error) throw error
      toast.success(`Attendance saved for ${date}!`)
    } catch (err) {
      toast.error(err.message || 'Failed to save')
    } finally {
      setSaving(false)
    }
  }

  const presentCount = students.filter(s => attendance[s.id] === 'present').length
  const absentCount = students.filter(s => attendance[s.id] === 'absent').length
  const percentage = students.length > 0 ? Math.round((presentCount / students.length) * 100) : 0

  return (
    <div className="animate-fade-in">
      <PageHeader title="Attendance" subtitle="Attendance">
        <button onClick={handleSave} disabled={saving || students.length === 0}
          className="btn-primary flex items-center gap-2 disabled:opacity-60">
          {saving ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : <Save size={15} />}
          Save Attendance
        </button>
      </PageHeader>

      {/* Filter Card */}
      <div className="card mb-5">
        <div className="card-header">
          <h3 className="card-title flex items-center gap-2">
            <Filter size={16} /> Filter
          </h3>
        </div>
        <div className="card-body">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            <div>
              <label className="form-label">Date</label>
              <input type="date" value={date} onChange={e => setDate(e.target.value)}
                className="form-input" max={today()} />
            </div>
            <div>
